mapper.select:
SELECT
id, article_name, article_outline, story_background, article_type, article_characteristics, article_content, voice_tone, voice_link, voice_file_path,
video_link, video_file_path, publish_status, create_time, update_time
FROM article

    res_state = 1

        AND article_name LIKE CONCAT('%', #{articleName,jdbcType=VARCHAR}, '%')


        AND voice_tone = #{voiceTone,jdbcType=VARCHAR}


        AND publish_status = #{publishStatus,jdbcType=SMALLINT}


        AND article_type = #{articleType,jdbcType=VARCHAR}


ORDER BY create_time DESC

