mapper.update:
UPDATE article
article_name = #{articleName,jdbcType=VARCHAR}, article_outline = #{articleOutline,jdbcType=VARCHAR}, story_background = #{storyBackground,jdbcType=VARCHAR}, image_desc = #{imageDesc,jdbcType=VARCHAR}, article_type = #{articleType,jdbcType=VARCHAR}, article_characteristics = #{articleCharacteristics,jdbcType=VARCHAR}, article_content = #{articleContent,jdbcType=VARCHAR}, voice_tone = #{voiceTone,jdbcType=VARCHAR}, voice_link = #{voiceLink,jdbcType=VARCHAR}, voice_file_path = #{voiceFilePath,jdbcType=VARCHAR}, video_link = #{videoLink,jdbcType=VARCHAR}, video_file_path = #{videoFilePath,jdbcType=VARCHAR}, publish_status = #{publishStatus,jdbcType=SMALLINT}, content_generated = #{contentGenerated,jdbcType=INTEGER}, res_state = #{resState,jdbcType=INTEGER}, update_time = #{updateTime,jdbcType=TIMESTAMP}
WHERE id = #{id,jdbcType=BIGINT}

UPDATE article
SET res_state = 0, update_time = NOW()
WHERE id = #{id,jdbcType=BIGINT}

UPDATE article
SET publish_status = #{publishStatus,jdbcType=SMALLINT}, update_time = NOW()
WHERE id = #{id,jdbcType=BIGINT}
